-- Optional: drop existing trigger to avoid duplicate errors when re-running
DROP TRIGGER IF EXISTS tr_change_playername ON player;

CREATE OR REPLACE FUNCTION log_player_name_changes()
RETURNS trigger
LANGUAGE plpgsql
AS $BODY$
BEGIN
  -- Use IS DISTINCT FROM to handle NULL-safe comparison
  IF NEW.player_name IS DISTINCT FROM OLD.player_name THEN
    INSERT INTO player_audits (player_id, old_player_name, changed_on)
    VALUES (OLD.id::integer, OLD.player_name, LOCALTIMESTAMP);
  END IF;

  RETURN NEW;
END;
$BODY$;

CREATE TRIGGER tr_change_playername
AFTER UPDATE OF player_name ON player
FOR EACH ROW
EXECUTE FUNCTION log_player_name_changes();

CREATE OR REPLACE FUNCTION total_loans()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  INSERT INTO loan_summary (account_id, total_loan_count)
  VALUES (
    NEW.account_id,
    (SELECT COUNT(*) FROM loan l WHERE l.account_id = NEW.account_id AND l.status = 'A')
  )
  ON CONFLICT (account_id) DO UPDATE
    SET total_loan_count = EXCLUDED.total_loan_count;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS tr_total_loans ON loan;

CREATE TRIGGER tr_total_loans
AFTER UPDATE OF status ON loan
FOR EACH ROW
EXECUTE FUNCTION total_loans();

