-- Create a 1-second timeout wrapper around transaction-scoped advisory locks
CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(l_key bigint)
RETURNS boolean
LANGUAGE plpgsql
AS $$
DECLARE
  deadline timestamptz := clock_timestamp() + interval '1 second';
BEGIN
  LOOP
    -- Try to acquire the lock without blocking (transaction-scoped; released on COMMIT/ROLLBACK)
    IF pg_try_advisory_xact_lock(l_key) THEN
      RETURN true;
    END IF;

    -- Stop trying after 1 second
    IF clock_timestamp() >= deadline THEN
      RETURN false;
    END IF;

    -- Sleep briefly to avoid busy-waiting
    PERFORM pg_sleep(0.01);
  END LOOP;
END;
$$;

