-- Correct trigger function: use the NEW row, parse JSONB safely, and strip query params from URL
CREATE OR REPLACE FUNCTION public.trigger_function()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  INSERT INTO public.destination_table (
    created_at,
    match_id,
    player_id,
    event_type,
    url,
    user_id
  )
  VALUES (
    NEW.created_at,
    NEW.match_id,
    NEW.player_id,
    NEW.event_type,
    split_part(NEW.url, '?', 1),
    NEW.data #>> '{local_storage,data,user_id}'
  );

  RETURN NEW;
END;
$$;

-- Correct trigger: call the function above on each inserted row
CREATE TRIGGER after_insert_source
AFTER INSERT ON public.source_table
FOR EACH ROW
EXECUTE FUNCTION public.trigger_function();

