-- Drop in the correct order to avoid dependency issues
DROP TABLE IF EXISTS disp CASCADE;
DROP TABLE IF EXISTS account CASCADE;

-- Create parent table without circular FK
CREATE TABLE account (
  account_id INT PRIMARY KEY NOT NULL,
  district_id INT NOT NULL,
  frequency TEXT NOT NULL,
  date DATE NOT NULL,
  FOREIGN KEY (district_id) REFERENCES district(district_id)
);

-- Child table references parent (1-to-many)
CREATE TABLE disp (
  disp_id INT PRIMARY KEY NOT NULL,
  client_id INT NOT NULL,
  account_id INT NOT NULL,
  type TEXT NOT NULL,
  FOREIGN KEY (client_id) REFERENCES client(client_id),
  FOREIGN KEY (account_id) REFERENCES account(account_id)
    ON UPDATE CASCADE
    ON DELETE CASCADE
);

-- Enforce: every existing account must have at least one disp
-- Use deferrable constraint triggers to avoid chicken-egg inserts

-- Function to check that an account has at least one disp
CREATE OR REPLACE FUNCTION check_account_has_disp() RETURNS trigger AS $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM disp WHERE account_id = NEW.account_id) THEN
    RAISE EXCEPTION 'Account % must have at least one associated disposition (disp)', NEW.account_id;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Function to prevent removing/moving the last disp of an account that still exists
CREATE OR REPLACE FUNCTION prevent_last_disp_removal() RETURNS trigger AS $$
DECLARE
  acc_id INT;
BEGIN
  acc_id := COALESCE(OLD.account_id, NEW.account_id);

  -- If the account is being deleted in the same transaction (e.g., ON DELETE CASCADE), skip this check
  IF NOT EXISTS (SELECT 1 FROM account WHERE account_id = acc_id) THEN
    RETURN NULL;
  END IF;

  -- Ensure there is still at least one disp for this account
  IF NOT EXISTS (SELECT 1 FROM disp WHERE account_id = acc_id) THEN
    RAISE EXCEPTION 'Cannot remove the last disposition of account %', acc_id;
  END IF;

  RETURN NULL;
END;
$$ LANGUAGE plpgsql;

-- Deferrable constraint trigger on account (allows inserting account and disp in same transaction)
DROP TRIGGER IF EXISTS trg_account_must_have_disp ON account;
CREATE CONSTRAINT TRIGGER trg_account_must_have_disp
AFTER INSERT OR UPDATE ON account
DEFERRABLE INITIALLY DEFERRED
FOR EACH ROW
EXECUTE FUNCTION check_account_has_disp();

-- Deferrable constraint triggers on disp to prevent leaving an account with zero disps
DROP TRIGGER IF EXISTS trg_prevent_last_disp_delete ON disp;
CREATE CONSTRAINT TRIGGER trg_prevent_last_disp_delete
AFTER DELETE ON disp
DEFERRABLE INITIALLY DEFERRED
FOR EACH ROW
EXECUTE FUNCTION prevent_last_disp_removal();

DROP TRIGGER IF EXISTS trg_prevent_last_disp_move ON disp;
CREATE CONSTRAINT TRIGGER trg_prevent_last_disp_move
AFTER UPDATE OF account_id ON disp
DEFERRABLE INITIALLY DEFERRED
FOR EACH ROW
EXECUTE FUNCTION prevent_last_disp_removal();

CREATE OR REPLACE FUNCTION public.generate_series_monthly(a date, b date)
RETURNS SETOF date
LANGUAGE plpgsql
IMMUTABLE
PARALLEL SAFE
ROWS 12
AS $function$
BEGIN
  RETURN QUERY
  SELECT gs::date
  FROM generate_series(
         date_trunc('month', a)::timestamp,
         date_trunc('month', b)::timestamp,
         interval '1 month'
       ) AS gs;
END;
$function$;

