EXPLAIN SELECT * FROM generate_series_monthly('2024-01-01', '2024-05-01');

CREATE OR REPLACE FUNCTION reindex_superhero_ids(p_publisher_id bigint)
RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
  seq_name text := 'id_seq_temp';
BEGIN
  -- Make sure no leftover temp sequence exists in this session
  DROP SEQUENCE IF EXISTS id_seq_temp;

  -- Create a new temp sequence that exists only for the current session
  CREATE TEMP SEQUENCE id_seq_temp MINVALUE 1 START WITH 1 INCREMENT BY 1;

  -- Use the text/regclass-based nextval so the sequence lookup happens at runtime
  UPDATE superhero
  SET hair_colour_id = nextval(seq_name::regclass)
  WHERE publisher_id = p_publisher_id;

  -- Clean up
  DROP SEQUENCE IF EXISTS id_seq_temp;
END;
$$;
